define(["jquery","local_gimidashboard/jszip","local_gimidashboard/dataTables","local_gimidashboard/dataTables.buttons","local_gimidashboard/dataTables.buttons.colVis","local_gimidashboard/dataTables.buttons.html5","local_gimidashboard/dataTables.buttons.print"],function($){function datatable(selector){const tables=document.querySelectorAll(selector);if(!tables.length){return}tables.forEach(element=>{if(!$.fn||!$.fn.dataTable){console.log("dataTable not found");return}if($.fn.dataTable.isDataTable(element)){console.log("dataTable.isDataTable not found");return}$(element).DataTable({autoWidth:false,responsive:true,pageLength:10,lengthMenu:[10,25,50,100],scrollX:true,select:true,layout:{topStart:"pageLength",topEnd:"search",bottomStart:"info",bottomEnd:["paging",{buttons:[{extend:"print",title:element.dataset.title||null},{extend:"copyHtml5",title:element.dataset.title||null},{extend:"excelHtml5",title:element.dataset.title||null},{extend:"csvHtml5",title:element.dataset.title||null}]}]}})})}return{datatable:datatable}});